import{_ as s,o as n,c as e,ag as i}from"./chunks/framework.brm5GKsQ.js";const g=JSON.parse('{"title":"Algorithm","description":"","frontmatter":{},"headers":[],"relativePath":"guide/algorithm.md","filePath":"guide/algorithm.md"}'),t={name:"guide/algorithm.md"};function l(o,a,r,p,h,d){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="algorithm" tabindex="-1">Algorithm <a class="header-anchor" href="#algorithm" aria-label="Permalink to &quot;Algorithm&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The algorithm works in multiple passes:</p><ol><li><strong>Setup</strong>: Initialize axis sizes, reset shrunk flag</li><li><strong>Layout Main Axis</strong>: Distribute items, apply grow/shrink</li><li><strong>Layout Cross Axis</strong>: Apply alignment</li></ol><h2 id="two-algorithm-variants" tabindex="-1">Two Algorithm Variants <a class="header-anchor" href="#two-algorithm-variants" aria-label="Permalink to &quot;Two Algorithm Variants&quot;">​</a></h2><p>Flexture provides two layout algorithm implementations:</p><table tabindex="0"><thead><tr><th>Algorithm</th><th>File</th><th>Default</th><th>Strengths</th></tr></thead><tbody><tr><td><strong>Zero-alloc</strong></td><td><code>layout-zero.ts</code></td><td>Yes</td><td>Faster for flat layouts, no GC pressure</td></tr><tr><td><strong>Classic</strong></td><td><code>layout.ts</code></td><td>No</td><td>Simpler code, good for debugging</td></tr></tbody></table><p>Both implement identical Yoga-compatible behavior. The zero-alloc version uses pre-allocated arrays and node-attached FlexInfo structs to eliminate temporary allocations during layout.</p><h2 id="grow-algorithm" tabindex="-1">Grow Algorithm <a class="header-anchor" href="#grow-algorithm" aria-label="Permalink to &quot;Grow Algorithm&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input: amount (extra space to distribute)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Calculate totalGrowAmount = sum of all flex-grow values for items not at max size</span></span>
<span class="line"><span>2. If no grow items, exit</span></span>
<span class="line"><span>3. Loop while amount remaining:</span></span>
<span class="line"><span>   a. amountPerGrow = remaining / totalGrowAmount</span></span>
<span class="line"><span>   b. For each item:</span></span>
<span class="line"><span>      - If item.grow &gt; 0:</span></span>
<span class="line"><span>        - grow = item.grow * amountPerGrow</span></span>
<span class="line"><span>        - If item has maxSize and size &gt;= maxSize: skip (fully grown)</span></span>
<span class="line"><span>        - If item has maxSize and size + grow &gt; maxSize:</span></span>
<span class="line"><span>          - grow = maxSize - size (cap at max)</span></span>
<span class="line"><span>          - totalGrowAmount -= item.grow (remove from next iteration)</span></span>
<span class="line"><span>        - finalSize = size + grow</span></span>
<span class="line"><span>        - Resize item to finalSize</span></span>
<span class="line"><span>        - remaining -= grow</span></span>
<span class="line"><span>        - If remaining ~= 0: done</span></span></code></pre></div><p><strong>Key insight</strong>: The algorithm iterates multiple times to handle items that hit their max size.</p><h2 id="shrink-algorithm" tabindex="-1">Shrink Algorithm <a class="header-anchor" href="#shrink-algorithm" aria-label="Permalink to &quot;Shrink Algorithm&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input: amount (space to remove)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Calculate totalShrinkAmount = sum of flex-shrink values for items above min size</span></span>
<span class="line"><span>2. If no shrinkable items, exit</span></span>
<span class="line"><span>3. Loop while amount remaining:</span></span>
<span class="line"><span>   a. amountPerShrink = remaining / totalShrinkAmount</span></span>
<span class="line"><span>   b. For each item:</span></span>
<span class="line"><span>      - If item.shrink &gt; 0 and size &gt; minSize:</span></span>
<span class="line"><span>        - shrink = item.shrink * amountPerShrink</span></span>
<span class="line"><span>        - maxShrink = size - minSize</span></span>
<span class="line"><span>        - If shrink &gt;= maxShrink:</span></span>
<span class="line"><span>          - shrink = maxShrink (cap at min)</span></span>
<span class="line"><span>          - totalShrinkAmount -= item.shrink (remove from next iteration)</span></span>
<span class="line"><span>        - finalSize = size - shrink</span></span>
<span class="line"><span>        - Resize item to finalSize</span></span>
<span class="line"><span>        - remaining -= shrink</span></span>
<span class="line"><span>        - If remaining ~= 0: done</span></span></code></pre></div><p><strong>Key insight</strong>: Shrink is proportional to <code>flex-shrink x flex-basis</code> (CSS spec compliant). Items with larger basis values shrink more, matching browser behavior.</p><h2 id="line-layout-flow" tabindex="-1">Line Layout Flow <a class="header-anchor" href="#line-layout-flow" aria-label="Permalink to &quot;Line Layout Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. _setItemSizes():</span></span>
<span class="line"><span>   - If availableSpace &gt; 0: grow items</span></span>
<span class="line"><span>   - If availableSpace &lt; 0: shrink items</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. setItemPositions():</span></span>
<span class="line"><span>   - Apply justifyContent alignment</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. _calcLayoutInfo():</span></span>
<span class="line"><span>   - Calculate cross axis max size for line</span></span></code></pre></div><h2 id="itempositioner-justify-content" tabindex="-1">ItemPositioner (justify-content) <a class="header-anchor" href="#itempositioner-justify-content" aria-label="Permalink to &quot;ItemPositioner (justify-content)&quot;">​</a></h2><p>The ItemPositioner handles:</p><ul><li>flex-start (default): items at start</li><li>flex-end: items at end</li><li>center: items centered</li><li>space-between: first/last at edges, rest evenly spaced</li><li>space-around: equal space around each item</li><li>space-evenly: equal space between and around items</li></ul><h2 id="rtl-and-logical-edges" tabindex="-1">RTL and Logical Edges <a class="header-anchor" href="#rtl-and-logical-edges" aria-label="Permalink to &quot;RTL and Logical Edges&quot;">​</a></h2><p>Both algorithms fully support RTL (right-to-left) layouts:</p><ul><li><code>DIRECTION_RTL</code> reverses the main axis for row layouts</li><li><code>EDGE_START</code>/<code>EDGE_END</code> resolve to physical edges based on direction</li><li>All margin, padding, and position edges respect direction</li></ul><p>The <code>resolveEdgeValue()</code> function maps logical edges to physical edges:</p><ul><li>In LTR: START -&gt; LEFT, END -&gt; RIGHT</li><li>In RTL: START -&gt; RIGHT, END -&gt; LEFT</li></ul><h2 id="baseline-alignment" tabindex="-1">Baseline Alignment <a class="header-anchor" href="#baseline-alignment" aria-label="Permalink to &quot;Baseline Alignment&quot;">​</a></h2><p>Baseline alignment is supported via <code>setBaselineFunc()</code>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setBaselineFunc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Return the baseline offset from the top</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> height </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // Example: 80% down</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>The baseline is used when <code>ALIGN_BASELINE</code> is set on the container&#39;s <code>alignItems</code>.</p><h2 id="key-differences-from-css-spec" tabindex="-1">Key Differences from CSS Spec <a class="header-anchor" href="#key-differences-from-css-spec" aria-label="Permalink to &quot;Key Differences from CSS Spec&quot;">​</a></h2><ol><li><strong>No order property</strong> -- Items laid out in insertion order</li><li><strong>No writing modes</strong> -- Horizontal-tb only</li></ol><h2 id="files" tabindex="-1">Files <a class="header-anchor" href="#files" aria-label="Permalink to &quot;Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>src/layout-zero.ts</code></td><td>Layout algorithm (default, ~2500 lines)</td></tr><tr><td><code>src/node-zero.ts</code></td><td>Node class with FlexInfo</td></tr><tr><td><code>src/index.ts</code></td><td>Default export</td></tr><tr><td><code>src/classic/layout.ts</code></td><td>Classic layout algorithm (~1800 lines)</td></tr><tr><td><code>src/classic/node.ts</code></td><td>Classic Node class</td></tr><tr><td><code>src/index-classic.ts</code></td><td>Classic export</td></tr></tbody></table>`,32)])])}const m=s(t,[["render",l]]);export{g as __pageData,m as default};
